import{_ as r,o as t,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"27. Flexible Working Arrangements","description":"","frontmatter":{"title":"27. Flexible Working Arrangements","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["employment","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/mspp/employment/27-flexible-working-arrangements.md","filePath":"ebas/mspp/employment/27-flexible-working-arrangements.md"}'),n={name:"ebas/mspp/employment/27-flexible-working-arrangements.md"};function a(i,e,l,p,m,g){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_27-flexible-working-arrangements" tabindex="-1">27. Flexible Working Arrangements <a class="header-anchor" href="#_27-flexible-working-arrangements" aria-label="Permalink to &quot;27. Flexible Working Arrangements&quot;">​</a></h1><p><strong>a.</strong> The Act entitles a specified Employee to request flexible working arrangements in specified circumstances.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>b.</strong> A specified Employee is a:</p><p><strong>(i)</strong> full time or part time Employee with at least 12 months continuous service with the employer; and</p><p><strong>(ii)</strong> regular casual Employee during a period of at least 12 months, and who has reasonable expectation of continuing employment by the Employer on a regular and systematic basis.</p><p><strong>c.</strong> The specified circumstances are the Employee:</p><p><strong>(i)</strong> is the parent, or has responsibility for the care, of a child who is of school age or younger;</p><p><strong>(ii)</strong> is a carer within the meaning of the Carer Recognition Act 2010 caring for someone who has a disability, a medical condition (including a terminal or chronic illness), a mental illness or is frail or aged;</p><p><strong>(iii)</strong> has a disability;</p><p><strong>(iv)</strong> is 55 or older;</p><p><strong>(v)</strong> is experiencing violence from a member of the Employee’s family; or</p><p><strong>(vi)</strong> provides care or support to a member of the Employee’s immediate family, or a member of the Employee’s household, who requires care or support because the member is experiencing violence from the member’s family.</p><p><strong>d.</strong> A specified Employee may request the Employer for a change in working arrangements because of the circumstances at subclause c.</p><p><strong>e.</strong> Changes in working arrangements may include but are not limited to hours of work, patterns of work and location of work.</p><p><strong>f.</strong> The request by the Employee must be in writing, set out the change sought and reasons for the change (This requirement is subject to any confidentiality requirements that may be relevant to matters involving family violence – see <a href="/eba/ebas/mspp/leave/82-family-violence-leave.html">clause 82</a>).</p><p><strong>g.</strong> The Employer must give the Employee a written response to the request within 21 days, stating whether the Employer grants or refuses the request. A request may only be refused on reasonable business grounds as described in the NES.</p><p><strong>h.</strong> Where the Employer refuses the request, the written response must include details of the reasons for the refusal.</p><p><strong>i.</strong> Where a request for flexible work arrangements is made, an Employee or Employer is entitled to meet with the other party to discuss:</p><p><strong>(i)</strong> the request;</p><p><strong>(ii)</strong> an alternative to the request; or</p><p><strong>(iii)</strong> reasons for a refusal on reasonable business grounds (as defined at</p><p><strong>j.</strong> An Employee or Employer may choose to be represented at a meeting under subclause i by a representative including a Union or employer organisation.</p><p><strong>k.</strong> The dispute resolution procedure in <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> of the Agreement will apply to any dispute / grievance arising in relation to a request for flexible working arrangements.</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>l.</strong> Other entitlements relevant to family violence can be found at <a href="/eba/ebas/mspp/leave/82-family-violence-leave.html">clause 82</a> (Family Violence Leave).</p><p>Plain language terms: flex work, flexible hours, WFH, work from home.</p>',27)])])}const u=r(n,[["render",a]]);export{c as __pageData,u as default};
